package main

import (
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"
)

var (
	allowedHosts = map[string]bool{
		"api.partner1.com": true,
		"api.partner2.com": true,
		"api.partner3.com": true,
	}
	
	// Block private/internal IP ranges
	privateIPBlocks = []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
		{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},
	}
)

func webhookProxyHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Get URL from query parameter
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter is required", http.StatusBadRequest)
		return
	}

	// Validate and sanitize URL
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		http.Error(w, "Invalid URL", http.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		http.Error(w, "Invalid URL scheme", http.StatusBadRequest)
		return
	}

	// Check if host is allowed
	if !isHostAllowed(parsedURL.Host) {
		http.Error(w, "Host not allowed", http.StatusForbidden)
		return
	}

	// Check for private IP addresses
	if isPrivateIP(parsedURL.Host) {
		http.Error(w, "Private IP addresses not allowed", http.StatusForbidden)
		return
	}

	// Create HTTP client with timeout
	client := &http.Client{
		Timeout: 10 * time.Second,
		Transport: &http.Transport{
			DisableKeepAlives: true,
		},
	}

	// Make request to target URL
	resp, err := client.Get(targetURL)
	if err != nil {
		http.Error(w, "Failed to fetch URL", http.StatusBadGateway)
		return
	}
	defer resp.Body.Close()

	// Copy response headers
	for key, values := range resp.Header {
		for _, value := range values {
			w.Header().Add(key, value)
		}
	}

	// Set status code
	w.WriteHeader(resp.StatusCode)

	// Copy response body
	_, err = io.Copy(w, resp.Body)
	if err != nil {
		// Log error but don't return it to client
		fmt.Printf("Error copying response body: %v\n", err)
	}
}

func isHostAllowed(host string) bool {
	// Check if host is in allowed list
	if allowedHosts[host] {
		return true
	}

	// Allow subdomains of allowed hosts
	for allowedHost := range allowedHosts {
		if strings.HasSuffix(host, "."+allowedHost) {
			return true
		}
	}

	return false
}

func isPrivateIP(host string) bool {
	// Extract IP from host (handle port if present)
	host = strings.Split(host, ":")[0]
	
	ip := net.ParseIP(host)
	if ip == nil {
		return false
	}

	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}

	return false
}

